import { orders, products, getNextOrderId } from "../data.js";
import type { Order, CreateOrderInput, OrderItem, ServiceResult } from "../types.js";

interface OrderListFilters {
  userId?: number;
  status?: string;
}

interface OrderListResult {
  orders: Order[];
  summary: {
    count: number;
    totalRevenue: number;
  };
}

interface EnrichedOrderItem extends OrderItem {
  productName: string;
}

interface EnrichedOrder extends Omit<Order, "items"> {
  items: EnrichedOrderItem[];
}

export function listOrders(filters: OrderListFilters): OrderListResult {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  // Calculate summary
  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrder(id: number): ServiceResult<EnrichedOrder> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { success: false, error: "Order not found", code: "NOT_FOUND" };
  }

  // Enrich order items with product names
  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    success: true,
    data: {
      ...order,
      items: enrichedItems,
    },
  };
}

export function createOrder(input: CreateOrderInput): ServiceResult<Order> {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    return {
      success: false,
      error: "userId and items are required",
      code: "VALIDATION_ERROR",
    };
  }

  if (input.items.length === 0) {
    return {
      success: false,
      error: "Order must have at least one item",
      code: "VALIDATION_ERROR",
    };
  }

  // Validate items and calculate totals
  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      return {
        success: false,
        error: `Product ${item.productId} not found`,
        code: "VALIDATION_ERROR",
      };
    }

    if (item.quantity <= 0) {
      return {
        success: false,
        error: "Quantity must be positive",
        code: "VALIDATION_ERROR",
      };
    }

    if (product.stock < item.quantity) {
      return {
        success: false,
        error: `Insufficient stock for ${product.name}`,
        code: "VALIDATION_ERROR",
      };
    }

    // Deduct stock
    product.stock -= item.quantity;

    const itemTotal = product.price * item.quantity;
    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += itemTotal;
  }

  const order: Order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending",
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return { success: true, data: order };
}

export function updateOrderStatus(
  id: number,
  status: string
): ServiceResult<Order> {
  const order = orders.find((o) => o.id === id);

  if (!order) {
    return { success: false, error: "Order not found", code: "NOT_FOUND" };
  }

  const validStatuses = ["pending", "confirmed", "shipped", "delivered"];

  if (!validStatuses.includes(status)) {
    return {
      success: false,
      error: `Invalid status. Must be one of: ${validStatuses.join(", ")}`,
      code: "VALIDATION_ERROR",
    };
  }

  // Validate status transitions
  const transitions: Record<string, string[]> = {
    pending: ["confirmed"],
    confirmed: ["shipped"],
    shipped: ["delivered"],
    delivered: [],
  };

  if (!transitions[order.status]?.includes(status)) {
    return {
      success: false,
      error: `Cannot transition from ${order.status} to ${status}`,
      code: "VALIDATION_ERROR",
    };
  }

  order.status = status as typeof order.status;

  return { success: true, data: order };
}

